import React, { useState, useEffect } from 'react';
import { useSearchParams, useNavigate } from 'react-router-dom';
import { CheckCircle, XCircle, RefreshCw, Info, ArrowRight, Mail } from 'lucide-react';

const EmailVerification = () => {
  const [searchParams] = useSearchParams();
  const [status, setStatus] = useState('initial');
  const [message, setMessage] = useState('');
  const navigate = useNavigate();

  useEffect(() => {
    const statusParam = searchParams.get('status');
    const token = searchParams.get('token');

    // If status is provided from backend redirect, use it
    if (statusParam) {
      if (statusParam === 'success') {
        setStatus('success');
        setMessage('Your email has been successfully verified! You can now login to your account.');
      } else if (statusParam === 'error') {
        setStatus('error');
        setMessage('Invalid or expired verification token');
      }
      return;
    }

    // If token is provided, verify it (direct access)
    if (token) {
      setStatus('success');
      setMessage('Your email has been successfully verified! You can now login to your account.');
      return;
    }

    // No token or status provided - show initial state (not error)
    setStatus('initial');
  }, [searchParams]);

  const handleGoToLogin = () => {
    navigate('/login');
  };

  const handleResendEmail = () => {
    navigate('/register');
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-gray-50 py-12 px-4 sm:px-6 lg:px-8">
      <div className="max-w-md w-full space-y-8">
        <div className="text-center">
          {status === 'initial' && (
              <div className="flex flex-col items-center space-y-4">
                <div className="flex items-center justify-center w-16 h-16 bg-primary-100 rounded-full">
                  <Mail className="h-8 w-8 text-primary-600" />
                </div>
                <h2 className="text-2xl font-bold text-gray-900">Email Verification</h2>
                <p className="text-gray-600">Please check your email and click the verification link to complete your registration.</p>

                <div className="bg-primary-50 border border-primary-200 rounded-lg p-4 max-w-sm">
                  <div className="flex items-start space-x-2">
                    <Info className="h-5 w-5 text-primary-600 mt-0.5 flex-shrink-0" />
                    <div className="text-left">
                      <p className="text-sm text-primary-800">
                        <strong>Next steps:</strong><br/>
                        1. Check your email inbox<br/>
                        2. Click the verification link<br/>
                        3. Return here to see confirmation<br/>
                        4. Login to your account
                      </p>
                    </div>
                  </div>
                </div>

              <div className="flex flex-col space-y-2 w-full">
                <button
                  onClick={handleGoToLogin}
                  className="inline-flex items-center justify-center px-6 py-3 border border-transparent text-base font-medium rounded-md text-white bg-primary-600 hover:bg-primary-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-primary-500 transition-colors"
                >
                  Go to Login
                </button>

                <button
                  onClick={handleResendEmail}
                  className="inline-flex items-center justify-center px-6 py-3 border border-gray-300 text-base font-medium rounded-md text-gray-700 bg-white hover:bg-gray-50 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-primary-500 transition-colors"
                >
                  <RefreshCw className="mr-2 h-4 w-4" />
                  Register Again
                </button>
              </div>
            </div>
          )}

          {status === 'success' && (
            <div className="flex flex-col items-center space-y-4">
              <div className="flex items-center justify-center w-16 h-16 bg-green-100 rounded-full">
                <CheckCircle className="h-8 w-8 text-green-600" />
              </div>
              <h2 className="text-2xl font-bold text-gray-900">Email Verified!</h2>
              <p className="text-gray-600">{message}</p>

              <button
                onClick={handleGoToLogin}
                className="inline-flex items-center px-6 py-3 border border-transparent text-base font-medium rounded-md text-white bg-primary-600 hover:bg-primary-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-primary-500 transition-colors"
              >
                Go to Login
                <ArrowRight className="ml-2 h-4 w-4" />
              </button>
            </div>
          )}

          {status === 'error' && (
            <div className="flex flex-col items-center space-y-4">
              <div className="flex items-center justify-center w-16 h-16 bg-red-100 rounded-full">
                <XCircle className="h-8 w-8 text-red-600" />
              </div>
              <h2 className="text-2xl font-bold text-gray-900">Verification Failed</h2>
              <p className="text-gray-600">{message}</p>

                <div className="bg-primary-50 border border-primary-200 rounded-lg p-4 max-w-sm">
                  <div className="flex items-start space-x-2">
                    <Info className="h-5 w-5 text-primary-600 mt-0.5 flex-shrink-0" />
                    <div className="text-left">
                      <p className="text-sm text-primary-800">
                        <strong>Possible reasons:</strong><br/>
                        • The verification link has expired<br/>
                        • The verification link has already been used<br/>
                        • The verification link is invalid
                      </p>
                    </div>
                  </div>
                </div>

              <div className="flex flex-col space-y-2 w-full">
                <button
                  onClick={handleResendEmail}
                  className="inline-flex items-center justify-center px-6 py-3 border border-gray-300 text-base font-medium rounded-md text-gray-700 bg-white hover:bg-gray-50 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-primary-500 transition-colors"
                >
                  <RefreshCw className="mr-2 h-4 w-4" />
                  Register Again
                </button>

                <button
                  onClick={handleGoToLogin}
                  className="inline-flex items-center justify-center px-6 py-3 border border-transparent text-base font-medium rounded-md text-white bg-primary-600 hover:bg-primary-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-primary-500 transition-colors"
                >
                  Go to Login
                </button>
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default EmailVerification;
